@@ -52,6 +52,25 @@ using namespace PatternMatch;

 /// Replace a select operand based on an equality comparison with the identity
 /// constant of a binop.
+/// Return true if V is or contains an ICmpInst with the samesign flag.
+static bool hasICmpWithSameSign(Value *V) {
+  SmallVector<Value *, 8> Worklist;
+  Worklist.push_back(V);
+  while (!Worklist.empty()) {
+    Value *Cur = Worklist.pop_back_val();
+    if (auto *ICmp = dyn_cast<ICmpInst>(Cur)) {
+      if (ICmp->hasSameSign())
+        return true;
+    }
+    if (auto *Sel = dyn_cast<SelectInst>(Cur)) {
+      Worklist.push_back(Sel->getCondition());
+      Worklist.push_back(Sel->getTrueValue());
+      Worklist.push_back(Sel->getFalseValue());
+    }
+  }
+  return false;
+}
